package cli

import "testing"

func TestStorageRunwayRanksFullestFirst(t *testing.T) {
	dbPath := seedNovelStore(t)
	out := runNovelCmd(t, newNovelStorageRunwayCmd, "--threshold-pct", "70", "--db", dbPath)

	var rows []storageRunwayRow
	mustUnmarshal(t, out, &rows)
	if len(rows) != 2 {
		t.Fatalf("rows = %d, want 2 devices", len(rows))
	}
	// DT01: 750/(750+250) = 75% — fullest first and over the 70% threshold.
	if rows[0].SerialNumber != "DT01" || rows[0].LocalUsedPct != 75.0 || !rows[0].OverThreshold {
		t.Fatalf("top row = %+v, want DT01 at 75%% over threshold", rows[0])
	}
	// DT02: 100/(100+900) = 10% — under threshold.
	if rows[1].SerialNumber != "DT02" || rows[1].OverThreshold {
		t.Fatalf("second row = %+v, want DT02 under threshold", rows[1])
	}
}
